import requests
def webhook(request):
    callback_url = request.GET.get('callback')
    if callback_url.startswith('https://api.trusted.com/'):
        response = requests.get(callback_url, timeout=5)
        return HttpResponse(response.content)
    return HttpResponse('Invalid URL')
